// Supabase devuelve un array en $input.first().json cuando se usa REST API.
// Aplanar y calcular días de atraso por cada ticket.
const tickets = $input.first().json;
const today = new Date();

return tickets.map(t => {
  const deadline = new Date(t.deadline);
  const daysOverdue = Math.floor((today - deadline) / (1000 * 60 * 60 * 24));
  const member = t.members || {};
  const project = t.projects || {};
  return {
    json: {
      ticket_id: t.id,
      title: t.title,
      priority: t.priority,
      estimate_hours: t.estimate_hours,
      risk_pct: t.risk_pct,
      deadline: t.deadline,
      status: t.status,
      days_overdue: daysOverdue,
      assignee_id: t.assignee_id,
      assignee_name: member.name || 'Sin asignar',
      assignee_email: member.email || '',
      project_id: t.project_id,
      project_name: project.name || 'Sin proyecto'
    }
  };
});

// Agrupa todos los tickets por assignee_email y construye
// un email consolidado para cada developer (no spam por ticket).
const items = $input.all();
const byAssignee = new Map();

for (const item of items) {
  const t = item.json;
  if (!t.assignee_email) continue;
  if (!byAssignee.has(t.assignee_email)) {
    byAssignee.set(t.assignee_email, { name: t.assignee_name, email: t.assignee_email, assignee_id: t.assignee_id, tickets: [] });
  }
  byAssignee.get(t.assignee_email).tickets.push(t);
}

const result = [];
for (const [email, data] of byAssignee) {
  const rows = data.tickets.map(t =>
    `<tr>
      <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.title}</td>
      <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.project_name}</td>
      <td style="padding:8px 12px;border-top:1px solid #e5e5e5">${t.priority}</td>
      <td style="padding:8px 12px;border-top:1px solid #e5e5e5;color:#dc2626;font-weight:600">${t.days_overdue} día${t.days_overdue !== 1 ? 's' : ''}</td>
    </tr>`
  ).join('');

  result.push({
    json: {
      assignee_email: email,
      assignee_name: data.name,
      assignee_id: data.assignee_id,
      ticket_count: data.tickets.length,
      tickets: data.tickets,
      email_html: `<div style="font-family:sans-serif;max-width:600px;margin:0 auto">
  <h2 style="color:#dc2626">⏰ Tenés ${data.tickets.length} ticket${data.tickets.length !== 1 ? 's' : ''} vencido${data.tickets.length !== 1 ? 's' : ''}</h2>
  <p>Hola <strong>${data.name}</strong>, los siguientes tickets superaron su fecha límite:</p>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#111;color:#fff">
      <th style="padding:8px 12px;text-align:left">Ticket</th>
      <th style="padding:8px 12px;text-align:left">Proyecto</th>
      <th style="padding:8px 12px;text-align:left">Prioridad</th>
      <th style="padding:8px 12px;text-align:left">Días de atraso</th>
    </tr>
    ${rows}
  </table>
  <p style="margin-top:16px">Por favor actualizá el estado de estos tickets o coordiná con tu manager.</p>
  <p style="color:#6b7280;font-size:13px">Meeting → Tickets PM · Cursor Buildathon 2026</p>
</div>`
    }
  });
}

return result;

// Obtener manager_email de la variable de entorno o del primer manager del equipo.
// Aquí construimos el resumen global para el manager.
const items = $input.all();
const allTickets = items.flatMap(i => i.json.tickets || []);

const byProject = new Map();
for (const t of allTickets) {
  if (!byProject.has(t.project_name)) byProject.set(t.project_name, []);
  byProject.get(t.project_name).push(t);
}

let projectSections = '';
for (const [project, pts] of byProject) {
  const rows = pts.map(t =>
    `<tr>
      <td style="padding:6px 12px;border-top:1px solid #e5e5e5">${t.title}</td>
      <td style="padding:6px 12px;border-top:1px solid #e5e5e5">${t.assignee_name}</td>
      <td style="padding:6px 12px;border-top:1px solid #e5e5e5;color:#dc2626">${t.days_overdue}d</td>
    </tr>`
  ).join('');
  projectSections += `<h3 style="margin:20px 0 8px;color:#111">${project} (${pts.length})</h3>
  <table style="border-collapse:collapse;width:100%">
    <tr style="background:#f5f5f5">
      <th style="padding:6px 12px;text-align:left">Ticket</th>
      <th style="padding:6px 12px;text-align:left">Asignado a</th>
      <th style="padding:6px 12px;text-align:left">Atraso</th>
    </tr>${rows}</table>`;
}

return [{
  json: {
    total: allTickets.length,
    manager_email: $env.MANAGER_EMAIL || '',
    summary_html: `<div style="font-family:sans-serif;max-width:700px;margin:0 auto">
  <h2 style="color:#dc2626">📊 Reporte diario: ${allTickets.length} ticket${allTickets.length !== 1 ? 's' : ''} vencido${allTickets.length !== 1 ? 's' : ''}</h2>
  <p>Los siguientes tickets superaron su deadline y siguen sin completarse:</p>
  ${projectSections}
  <p style="color:#6b7280;font-size:13px;margin-top:24px">Meeting → Tickets PM · ${new Date().toLocaleDateString('es-SV')}</p>
</div>`
  }
}];

// Registra en la tabla notifications un log por cada developer notificado.
const items = $input.all();
return items.map(item => ({
  json: {
    _insert_payload: JSON.stringify({
      member_id: item.json.assignee_id || null,
      channel: 'email',
      template: 'deadline_overdue',
      status: 'sent',
      sent_at: new Date().toISOString(),
      metadata: { ticket_count: item.json.ticket_count, to: item.json.assignee_email }
    })
  }
}));
